mapper.select:
SELECT count(1) totalCount,
	   if(ROUND(sum(c.total_amount)/10000,2) is null,0,ROUND(sum(c.total_amount)/10000,2)) totalAmount,
	   if(ROUND(sum(c.breach_amount-c.receive_breach_amount),2) is null,0,ROUND(sum(c.breach_amount-c.receive_breach_amount),2)) totalBreachAmount,
       if(ROUND(sum(c.total_number),3) is null,0,ROUND(sum(c.total_number),3)) totalNumber,
	   #{statisticsType} statisticsType
FROM t_ctr_contract c
WHERE
      c.contract_type = 'S'
	  and c.contract_status != 'C'
	  and c.contract_status != 'D'
	  and c.enterprise_id = 44
	  and c.match_credit_flg=true
	  AND c.breach_days > 0

	AND c.performance_status = #{statisticsType}


	and c.match_user_id not in

		#{hgMatchUserIdList[${index}]}

SELECT count(1) totalCount, if(ROUND(SUM(b.total_amount - b.billed_amount)/10000,2) is null,0,ROUND(SUM(b.total_amount - b.billed_amount)/10000,2)) totalAmount, 'A' statisticsType, b.our_company_name ourCompanyName, '待收进项发票' statisticsTypeName, '1' dispOrderNo, #{businessType} businessType FROM t_ctr_contract b WHERE b.contract_status != 'C' and b.contract_type='B' and b.business_type='ZY-BB' and b.enterprise_id = 44 and b.seal_flg = true and b.total_amount > b.billed_amount
and b.our_company_name in
#{item}
AND b.our_company_name = #{ourCompanyName}
AND b.match_credit_flg = TRUE
AND b.match_credit_flg = FALSE
and b.match_user_id not in
#{hgMatchUserIdList[${index}]}

SELECT count(1) totalCount, if(ROUND(SUM(s.total_amount - s.billed_amount)/10000,2) is null,0,ROUND(SUM(s.total_amount - s.billed_amount)/10000,2)) totalAmount, 'B' statisticsType, s.our_company_name ourCompanyName, '已收未开发票' statisticsTypeName, '2' dispOrderNo, #{businessType} businessType, s.match_credit_flg matchCreditFlg FROM t_ctr_contract s INNER JOIN t_ctr_contract_rela r ON s.id = r.sell_contract_id INNER JOIN t_ctr_contract b ON r.buy_contract_id = b.id WHERE s.contract_status != 'C' and s.contract_type='S' and s.business_type='ZY-BB' and s.enterprise_id = 44 and b.billed_amount >= b.total_amount and s.total_amount > s.billed_amount
and s.our_company_name in
#{item}
AND s.our_company_name = #{ourCompanyName}
AND s.match_credit_flg = TRUE
AND s.match_credit_flg = FALSE
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}

SELECT count(1) totalCount, if(ROUND(SUM(s.total_amount)/10000,2) is null,0,ROUND(SUM(s.total_amount)/10000,2)) totalAmount, 'C' statisticsType, s.our_company_name ourCompanyName, '未收已开发票' statisticsTypeName, '3' dispOrderNo, #{businessType} businessType FROM t_ctr_contract s INNER JOIN t_ctr_contract_rela r ON s.id=r.sell_contract_id INNER JOIN t_ctr_contract b ON r.buy_contract_id=b.id WHERE s.contract_status != 'C' and s.contract_type='S' and s.business_type='ZY-BB' and s.enterprise_id = 44 and b.total_amount > b.billed_amount and s.billed_amount >= s.total_amount
and s.our_company_name in
#{item}
AND s.our_company_name = #{ourCompanyName}
AND s.match_credit_flg = TRUE
AND s.match_credit_flg = FALSE
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}

SELECT count(1) totalCount, if(ROUND(SUM(s.total_amount - s.billed_amount)/10000,2) is null,0,ROUND(SUM(s.total_amount - s.billed_amount)/10000,2)) totalAmount, 'D' statisticsType, s.our_company_name ourCompanyName, '待开销项发票' statisticsTypeName, '4' dispOrderNo, #{businessType} businessType FROM t_ctr_contract s WHERE s.contract_status != 'C' and s.contract_type='S' and s.business_type='ZY-BB' and s.enterprise_id = 44 and s.seal_flg = true and s.total_amount > s.billed_amount
and s.our_company_name in
#{item}
AND s.our_company_name = #{ourCompanyName}
AND s.match_credit_flg = TRUE
AND s.match_credit_flg = FALSE
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}

SELECT count(1) totalCount, if(ROUND(SUM(t.total_amount - t.dealed_amount)/10000,2) is null,0,ROUND(SUM(t.total_amount - t.dealed_amount)/10000,2)) totalAmount, 'E' statisticsType, t.our_company_name ourCompanyName, '代采赊销应付' statisticsTypeName, '5' dispOrderNo, #{businessType} businessType FROM t_ctr_dcsx t WHERE t.status != 'C' and t.enterprise_id = 44 and t.seal_flg = true AND t.business_type = 'ZY-BB' and t.total_amount > t.dealed_amount
and t.our_company_name in
#{item}
AND t.our_company_name = #{ourCompanyName}
and t.match_user_id not in
#{hgMatchUserIdList[${index}]}

SELECT count(1) totalCount, if(ROUND(SUM(b.total_amount - b.dealed_amount)/10000,2) is null,0,ROUND(SUM(b.total_amount - b.dealed_amount)/10000,2)) totalAmount, 'F' statisticsType, b.our_company_name ourCompanyName, '代采应付' statisticsTypeName, '6' dispOrderNo, #{businessType} businessType FROM t_ctr_contract b WHERE b.contract_status != 'C' and b.contract_type='B' and b.business_type='ZY-BB' and b.enterprise_id = 44 and b.seal_flg = true and b.match_credit_flg=false and b.total_amount > b.dealed_amount
and b.our_company_name in
#{item}
AND b.our_company_name = #{ourCompanyName}
AND b.match_credit_flg = TRUE
AND b.match_credit_flg = FALSE
and b.match_user_id not in
#{hgMatchUserIdList[${index}]}

SELECT count(1) totalCount, if(ROUND(SUM(s.total_amount - s.dealed_amount)/10000,2) is null,0,ROUND(SUM(s.total_amount - s.dealed_amount)/10000,2)) totalAmount, 'G' statisticsType, '已付款未发货' statisticsTypeName, '7' dispOrderNo, #{businessType} businessType FROM t_ctr_contract s INNER JOIN t_ctr_contract_rela r ON s.id=r.sell_contract_id INNER JOIN t_ctr_contract b ON r.buy_contract_id=b.id WHERE s.contract_status != 'C' and s.contract_type='S' and s.enterprise_id = 44 and s.business_type='ZY-BB' and s.match_credit_flg=true and b.dealed_amount >= b.total_amount and s.total_number > s.warehouse_number and s.total_amount > s.dealed_amount
and s.our_company_name in
#{item}
AND s.our_company_name = #{ourCompanyName}
AND s.match_credit_flg = TRUE
AND s.match_credit_flg = FALSE
and s.match_user_id not in
#{hgMatchUserIdList[${index}]}

SELECT if(ROUND(SUM(s.total_amount)/10000,2) is null,0,ROUND(SUM(s.total_amount)/10000,2)) totalAmount, #{businessType} businessType, s.match_credit_flg matchCreditFlg, WEEK(#{startDate}) week, date_format(#{startDate}, '%Y') year, date_format(#{startDate}, '%Y-%m-%d') startDate FROM t_ctr_contract s WHERE s.contract_status != 'C' and s.contract_type='S' and s.enterprise_id = 44 and s.business_type=#{businessType}
and s.match_credit_flg=#{matchCreditFlg}
and s.seal_date BETWEEN #{startDate} and #{endDate}

SELECT if(ROUND(SUM(s.total_amount)/10000,2) is null,0,ROUND(SUM(s.total_amount)/10000,2)) totalAmount, #{businessType} businessType, s.match_credit_flg matchCreditFlg, #{month} month FROM t_ctr_contract s WHERE s.contract_status != 'C' and s.contract_type='S' and s.enterprise_id = 44 and s.business_type=#{businessType}
and s.match_credit_flg=#{matchCreditFlg}
and date_format(s.seal_date, '%Y-%m') = #{month}
